  FOOTER   "plantillas/fin.html" 
  PROJECTION
	"init=epsg:32718"
  END
  METADATA
	"wms_encoding" "LATIN1"
	"layer_encoding" "LATIN1"
	"wms_group_title" "Climatología microcuenca Huacrahuacho"
	"queryable" "true"
	"wms_metadataurl_type" "TC211"
