  END
  CLASS
	NAME "Temperatura media (°C)"
    EXPRESSION ([pixel] = -99999)
    COLOR -1 -1 -1
  END
  CLASS
	NAME "5 - 6"
    EXPRESSION ([pixel] >= 5 AND [pixel] < 6)
    COLOR 120 255 221
  END
  CLASS
	NAME "6 - 7"
    EXPRESSION ([pixel] >= 6 AND [pixel] < 7)
    COLOR 191 255 200
  END
  CLASS
	NAME "7 - 8"
    EXPRESSION ([pixel] >= 7 AND [pixel] < 8)
    COLOR 102 217 129
  END
  CLASS
	NAME "8 - 9"
    EXPRESSION ([pixel] >= 8 AND [pixel] < 9)
    COLOR 154 217 52
  END
  CLASS
	NAME "9 - 10"
    EXPRESSION ([pixel] >= 9 AND [pixel] < 10)
    COLOR 204 230 76
  END
  CLASS
	NAME "10 - 11"
    EXPRESSION ([pixel] >= 10 AND [pixel] <= 11)
    COLOR 208 255 115
  END
END # Layer